const item = $input.item.json;

try {
  let aiResponse = item.data || item.response || item.message || item.output || item;

  if (typeof aiResponse === 'string') {
    aiResponse = aiResponse
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .replace(/^json/, '')
      .trim();

    aiResponse = JSON.parse(aiResponse);
  }

  const analise = aiResponse.analise_individual || [];

  const postsAprovados = analise.filter(p => p.status === 'aprovado').length;
  const postsReprovados = analise.filter(p => p.status === 'reprovado').length;

  return {
    nota_final_geral: aiResponse.nota_final_geral || 0,
    status_geral: aiResponse.status_geral || 'erro',

    // 🔥 agora calculado corretamente
    posts_aprovados: postsAprovados,
    posts_reprovados: postsReprovados,

    recomendacao: aiResponse.recomendacao || 'Sem recomendação',

    blog: analise.find(p => p.plataforma === 'blog') || null,
    instagram: analise.find(p => p.plataforma === 'instagram') || null,
    linkedin: analise.find(p => p.plataforma === 'linkedin') || null,
    x: analise.find(p => p.plataforma === 'x') || null,
    whatsapp: analise.find(p => p.plataforma === 'whatsapp') || null,

    analise_individual: analise
  };

} catch (error) {
  return {
    erro: true,
    mensagem: error.message,
    resposta_original: item
  };
}

try {
  let raw = $input.item.json.content;

  // Limpeza
  raw = raw
    .replace(/```json|```/g, '')
    .replace(/\n/g, '')
    .replace(/\r/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  // Extrai JSON
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}') + 1;

  if (start === -1 || end === 0) {
    throw new Error('JSON não encontrado ou truncado');
  }

  let jsonStr = raw.substring(start, end);
  let data;

  try {
    data = JSON.parse(jsonStr);
  } catch (parseError) {
    // Detecta se foi truncado no meio de uma string
    if (jsonStr.includes('"motivo": "') && !jsonStr.endsWith('}')) {
      throw new Error('RESPOSTA TRUNCADA - Aumente max_tokens da IA para 4000. A IA parou no meio da análise.');
    }

    // Tenta corrigir JSON truncado
    let fixed = jsonStr;

    const openBraces = (fixed.match(/{/g) || []).length;
    const closeBraces = (fixed.match(/}/g) || []).length;
    const openBrackets = (fixed.match(/\[/g) || []).length;
    const closeBrackets = (fixed.match(/\]/g) || []).length;
    const quotes = (fixed.match(/"/g) || []).length;

    // Fecha aspas ímpares
    if (quotes % 2 !== 0) {
      fixed += '"';
    }

    // Fecha estruturas abertas
    if (openBraces > closeBraces) {
      fixed += '}'.repeat(openBraces - closeBraces);
    }

    if (openBrackets > closeBrackets) {
      fixed += ']'.repeat(openBrackets - closeBrackets);
    }

    try {
      data = JSON.parse(fixed);
      data._corrigido = true;
      data._aviso = 'JSON foi corrigido automaticamente - resposta pode estar incompleta';
    } catch (secondError) {
      throw new Error(`ERRO CRÍTICO: Aumente max_tokens para 4000. Detalhes: ${parseError.message}`);
    }
  }

  // Validação
  if (data.analise_detalhada && Array.isArray(data.analise_detalhada)) {
    const esperado = data.imagens_analisadas || 0;
    const recebido = data.analise_detalhada.length;

    if (recebido < esperado) {
      data._aviso_truncamento = `ATENÇÃO: Esperado ${esperado} análises, recebido apenas ${recebido}. Aumente max_tokens.`;
    }

    data.analise_detalhada = data.analise_detalhada.map((item, index) => ({
      imagem: item.imagem || (index + 1),
      link_imagem: item.link_imagem || "URL_NAO_FORNECIDA",
      status: item.status || "Erro",
      motivo: item.motivo || "Análise incompleta (truncada)"
    }));
  }

  return {
    json: {
      decisao_geral: data.decisao_geral || "ERRO",
      imagens_aprovadas: data.imagens_aprovadas || 0,
      imagens_rejeitadas: data.imagens_rejeitadas || 0,
      imagens_analisadas: data.imagens_analisadas || 0,
      recomendacao_final: data.recomendacao_final || "REVISAR_MANUALMENTE",
      analise_detalhada: data.analise_detalhada || [],
      precisa_regerar: (data.recomendacao_final || "").includes("REGERAR"),
      pode_publicar: data.decisao_geral === "APROVADO",
      erro: false,
      json_corrigido: data._corrigido || false,
      aviso_truncamento: data._aviso_truncamento || data._aviso || null
    }
  };

} catch (error) {
  return {
    json: {
      erro: true,
      erro_mensagem: error.message,
      erro_resposta_original: $input.item.json.content,
      decisao_geral: "ERRO",
      imagens_aprovadas: 0,
      imagens_rejeitadas: 0,
      imagens_analisadas: 0,
      recomendacao_final: "REVISAR_MANUALMENTE",
      analise_detalhada: [],
      precisa_regerar: true,
      pode_publicar: false
    }
  };
}
